tion normalizeRecord(value, field, normalizeValue) {\\\\\\\\\\\\\\\\n  if (!value || typeof value !== \\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\"object\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\" || Array.isArray(value)) {\\\\\\\\\\\\\\\\n    throw new TypeError(`${field} must be an object.`);\\\\\\\\\\\\\\\\n  }\\\\\\\\\\\\\\\\n\\\\\\\\\\\\\\\\n  return Object.fromEntries(\\\\\\\\\\\\\\\\n    Object.entries(value).map(([key, item]) => {\\\\\\\\\\\\\\\\n      const normalizedKey = String(key).trim();\\\\\\\\\\\\\\\\n      if (!normalizedKey) {\\\\\\\\\\\\\\\\n        throw new TypeError(`${field} keys must be non-empty strings.`);\\\\\\\\\\\\\\\\n      }\\\\\\\\\\\\\\\\n      return [normalizedKey, normalizeValue(item, normalizedKey)];\\\\\\\\\\\\\\\\n    }),\\\\\\\\\\\\\\\\n  );\\\\\\\\\\\\\\\\n}\\\\\\\\\\\\\\\\n\\\\\\\\\\\\\\\\nfunction normalizeSize(value, key) {\\\\\\\\\\\\\\\\n  if (!value || typeof value !== \\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\"object\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\" || Array.isArray(value)) {\\\\\\\\\\\\\\\\n    throw new TypeError(`sizes.${key} must be an object.`);\\\\\\\\\\\\\\\\n  }\\\\\\\\\\\\\\\\n  if (typeof value.value !== \\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\"string\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\" || !value.value.trim()) {\\\\\\\\\\\\\\\\n    throw new TypeError(`sizes.${key}.value must be a non-empty string.`);\\\\\\\\\\\\\\\\n  }\\\\\\\\\\\\\\\\n\\\\\\\\\\\\\\\\n  const normalized = { value: value.value.trim() };\\\\\\\\\\\\\\\\n  if (value.system !== undefined) {\\\\\\\\\\\\\\\\n    if (typeof value.system !== \\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\"string\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\" || !value.system.trim()) {\\\\\\\\\\\\\\\\n      throw new TypeError(`sizes.${key}.system must be a non-empty string.`);\\\\\\\\\\\\\\\\n    }\\\\\\\\\\\\\\\\n    normalized.system = value.system.trim();\\\\\\\\\\\\\\\\n  }\\\\\\\\\\\\\\\\n  if (value.notes !== undefined) {\\\\\\\\\\\\\\\\n    if (typeof value.notes !== \\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\"string\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\"